+    #[test]
+    fn check_metric_drift_reports_actual_compared_count_when_under_five() {
+        let baseline = vec![
+            BaselineMetricItem {
+                id: "A".to_string(),
+                value: 3.0,
+            },
+            BaselineMetricItem {
+                id: "B".to_string(),
+                value: 2.0,
+            },
+            BaselineMetricItem {
+                id: "C".to_string(),
+                value: 1.0,
+            },
+        ];
+        let current = vec![
+            BaselineMetricItem {
+                id: "X".to_string(),
+                value: 3.0,
+            },
+            BaselineMetricItem {
+                id: "Y".to_string(),
+                value: 2.0,
+            },
+            BaselineMetricItem {
+                id: "Z".to_string(),
+                value: 1.0,
+            },
+        ];
+
+        let mut alerts = Vec::new();
+        check_metric_drift("pr", &baseline, &current, &mut alerts);
+
+        assert_eq!(alerts.len(), 1);
+        assert_eq!(alerts[0].message, "3 of top-3 rankings changed");
+        assert_eq!(alerts[0].baseline_value, 3.0);
+        assert_eq!(alerts[0].current_value, 0.0);
+        assert_eq!(alerts[0].delta, 3.0);
+    }
+
